// PATCH: Add local budget burn-down projection across budgets, categories, and transactions.

type budgetBurnResult struct {
	CategoryID        string  `json:"category_id"`
	CategoryName      string  `json:"category_name"`
	Target            float64 `json:"target"`
	Spent             float64 `json:"spent"`
	DaysRemaining     int     `json:"days_remaining"`
	ProjectedEndSpend float64 `json:"projected_end_spend"`
	OverUnderFlag     string  `json:"over_under_flag"`
}

func newBudgetsBurnCmd(flags *rootFlags) *cobra.Command {
	var period string
	var dbPath string
	cmd := &cobra.Command{
		Use:         "burn",
		Short:       "Project budget period spend from local transactions",
		Annotations: map[string]string{"mcp:read-only": "true"},
		Example: strings.Trim(`
  # Project May 2026 category spend against local budget targets
  lunch-money-pp-cli budgets burn --period 2026-05 --json
  `, "\n"),
		RunE: func(cmd *cobra.Command, args []string) error {
			if dryRunOK(flags) {
				return nil
			}
			start, end, err := monthBounds(period)
			if err != nil {
				return usageErr(fmt.Errorf("invalid --period %q: %w", period, err))
			}
			db, err := openLocalStore(cmd.Context(), dbPath)
			if err != nil {
				return fmt.Errorf("budgets burn: %w", err)
			}
			defer db.Close()
			results, err := buildBudgetBurn(cmd.Context(), db, start, end)
			if err != nil {
				return fmt.Errorf("budgets burn: %w", err)
			}
			w := cmd.OutOrStdout()
			if flags.asJSON {
				return json.NewEncoder(w).Encode(results)
			}
			fmt.Fprintln(w, "Category ID\tCategory Name\tTarget\tSpent\tDays Remaining\tProjected End Spend\tOver/Under")
			for _, r := range results {
				fmt.Fprintf(w, "%s\t%s\t%.2f\t%.2f\t%d\t%.2f\t%s\n",
					r.CategoryID, r.CategoryName, r.Target, r.Spent, r.DaysRemaining, r.ProjectedEndSpend, r.OverUnderFlag)
			}
			return nil
		},
	}
	cmd.Flags().StringVar(&period, "period", time.Now().Format("2006-01"), "Budget period in YYYY-MM format")
	cmd.Flags().StringVar(&dbPath, "db", "", "Database path")
	return cmd
}

func buildBudgetBurn(ctx context.Context, db *store.Store, start, end time.Time) ([]budgetBurnResult, error) {
	categoryNames, err := loadCategoryNames(ctx, db)
	if err != nil {
		return nil, err
	}
	budgetObjects, err := loadResourceObjects(ctx, db, "budgets")
	if err != nil {
		return nil, err
	}
	targets := map[string]float64{}
	for _, obj := range budgetObjects {
		categoryID := localID(obj, "category_id")
		if categoryID == "" || !inMonth(localString(obj, "start_date"), start, end) {
			continue
		}
		target := localFloat(obj, "amount")
		if localLookup(obj, "to_base") != nil {
			target = localFloat(obj, "to_base")
		}
		targets[categoryID] = target
	}

	spent := map[string]float64{}
	txs, err := loadLocalTransactions(ctx, db)
	if err != nil {
		return nil, err
	}
	for _, tx := range txs {
		if tx.CategoryID == "" || tx.Date.Before(start) || tx.Date.After(end) || !budgetBurnCountsTransaction(tx) {
			continue
		}
		spent[tx.CategoryID] += tx.Amount
	}

	periodDays, daysElapsed, daysRemaining := budgetPeriodProgress(start, end)
	seen := map[string]bool{}
	for id := range targets {
		seen[id] = true
	}
	for id := range spent {
		seen[id] = true
	}
	results := make([]budgetBurnResult, 0)
	for id := range seen {
		projected := spent[id]
		if daysElapsed > 0 {
			projected = spent[id] * float64(periodDays) / float64(daysElapsed)
		}
		results = append(results, budgetBurnResult{
			CategoryID:        id,
			CategoryName:      categoryNames[id],
			Target:            targets[id],
			Spent:             spent[id],
			DaysRemaining:     daysRemaining,
			ProjectedEndSpend: projected,
			OverUnderFlag:     burnFlag(projected, targets[id]),
		})
	}
	sort.SliceStable(results, func(i, j int) bool {
		if results[i].OverUnderFlag != results[j].OverUnderFlag {
			return results[i].OverUnderFlag < results[j].OverUnderFlag
		}
		if results[i].CategoryName != results[j].CategoryName {
			return results[i].CategoryName < results[j].CategoryName
		}
		// Final tie-break on CategoryID to keep output deterministic
		// even when CategoryName is empty for every row.
		return results[i].CategoryID < results[j].CategoryID
	})
	return results, nil
}

func budgetBurnCountsTransaction(tx localTransaction) bool {
	// PATCH: Match Lunch Money's default transaction-list tier so expanded
	// local stores do not double-count split parents or grouped children.
	// PATCH(budget-exclude): also skip status=exclude transactions, which Lunch
	// Money removes from budget calculations the same way the web UI does;
	// otherwise excluded rows inflate spent totals and the over/under flag.
	if strings.EqualFold(tx.Status, "exclude") || strings.EqualFold(tx.Status, "excluded") {
		return false
	}
	return !tx.IsSplitParent && tx.GroupParentID == ""
}

func budgetPeriodProgress(start, end time.Time) (int, int, int) {
	periodDays := int(end.Sub(start).Hours()/24) + 1
	today := time.Date(time.Now().Year(), time.Now().Month(), time.Now().Day(), 0, 0, 0, 0, time.Local)
	if today.Before(start) {
		return periodDays, 0, periodDays
	}
	if today.After(end) {
		return periodDays, periodDays, 0
	}
	return periodDays, int(today.Sub(start).Hours()/24) + 1, int(end.Sub(today).Hours() / 24)
}

func burnFlag(projected, target float64) string {
	if math.Abs(projected-target) <= 0.01 {
		return "tracking"
	}
	if target == 0 {
		if projected > 0 {
			return "over"
		}
		return "tracking"
	}
	if projected > target {
		return "over"
	}
	return "under"
}
